/* ── CURSOR ── */
const dot = document.getElementById('cur-dot');
const ring = document.getElementById('cur-ring');
let mx=0,my=0,rx=0,ry=0;
document.addEventListener('mousemove', e => { mx=e.clientX; my=e.clientY; });
(function loop() {
  dot.style.cssText = `left:${mx}px;top:${my}px`;
  rx += (mx-rx)*.1; ry += (my-ry)*.1;
  ring.style.cssText = `left:${rx}px;top:${ry}px`;
  requestAnimationFrame(loop);
})();
document.addEventListener('mouseover', e => {
  if (e.target.closest('a,button,.proj-row,.svc,.step')) document.body.classList.add('c-hover');
});
document.addEventListener('mouseout', e => {
  if (e.target.closest('a,button,.proj-row,.svc,.step')) document.body.classList.remove('c-hover');
});

/* ── LOADER ── */
window.addEventListener('load', () => {
  setTimeout(() => {
    document.getElementById('loader').classList.add('gone');
    document.querySelectorAll('#hero .rv').forEach((el,i) => {
      setTimeout(() => el.classList.add('in'), 200 + i*100);
    });
  }, 1800);
});

/* ── SCROLL: progress + nav ── */
const nav = document.getElementById('nav');
const prog = document.getElementById('prog');
const secs = ['hero','about','work','process','contact'];
window.addEventListener('scroll', () => {
  const pct = window.scrollY / (document.body.scrollHeight - window.innerHeight);
  prog.style.width = (pct * 100) + '%';
  nav.classList.toggle('scrolled', window.scrollY > 50);
  secs.forEach(id => {
    const el = document.getElementById(id);
    if (!el) return;
    const t = el.getBoundingClientRect().top;
    const lk = document.querySelector(`[data-s="${id}"]`);
    if (lk) lk.classList.toggle('active', t < 120 && t > -el.offsetHeight + 120);
  });
});

/* ── MOBILE NAV ── */
const burger = document.getElementById('burger');
const mobNav = document.getElementById('mob-nav');
burger.addEventListener('click', () => {
  burger.classList.toggle('open');
  mobNav.classList.toggle('open');
  document.body.classList.toggle('nav-open');
});
mobNav.querySelectorAll('.mob-lk').forEach(l => l.addEventListener('click', () => {
  burger.classList.remove('open');
  mobNav.classList.remove('open');
  document.body.classList.remove('nav-open');
}));

/* ── REVEAL ── */
const obs = new IntersectionObserver(entries => {
  entries.forEach(e => { if (e.isIntersecting) { e.target.classList.add('in'); obs.unobserve(e.target); } });
}, { threshold: 0.07 });
function initReveal() {
  document.querySelectorAll('.rv:not(.in)').forEach(el => obs.observe(el));
}

/* ── TICKERS ── */
function buildTicker(id, items, cls) {
  const el = document.getElementById(id);
  const all = [...items, ...items];
  el.innerHTML = all.map(t => `<span class="${cls}">${t}<span class="dot"></span></span>`).join('');
}
const tkItems = ['Strategy','Brand Identity','Web Development','AI & Automation','Social Media','Print & Design','Morocco','MENA','Precision','Strategy','Brand Identity','Web Development','AI & Automation','Social Media'];
buildTicker('ticker', tkItems, 'ticker-item');

const bandItems = ['Design','Development','Automation','Branding','Strategy','Visibility','Growth','Precision','Design','Development','Automation','Branding','Strategy','Visibility','Growth','Precision'];
function buildBand(id) {
  const el = document.getElementById(id);
  const all = [...bandItems, ...bandItems];
  el.innerHTML = all.map(t => `<span class="band-item">${t}<i class="ph ph-diamond-four"></i></span>`).join('');
}
buildBand('band');
buildBand('band2');

/* ── BUILD PROJECTS ── */
function buildProjects() {
  const list = document.getElementById('projList');
  PROJECTS.forEach((p, i) => {
    const even = i % 2 === 0;
    const row = document.createElement('div');
    row.className = 'proj-row rv';
    const imgPane = `
      <div class="pv">
        <img src="${p.img}" alt="${p.name}" loading="lazy">
        <div class="pv-over"></div>
        <div class="pv-badge"><i class="ph ph-arrow-up-right"></i></div>
      </div>`;
    const infoPane = `
      <div class="pi${even ? '' : ' left-border'}">
        <div class="pi-top">
          <div class="pi-meta">
            <span class="pi-cat">${p.category}</span>
            <span class="pi-year">${p.year}</span>
          </div>
          <h3 class="pi-name">${p.index} — ${p.name}</h3>
          <p class="pi-hl">${p.headline}</p>
          <div class="pi-tags">${p.tags.map(t=>`<span class="pi-tag">${t}</span>`).join('')}</div>
          <p class="pi-desc">${p.desc}</p>
        </div>
        <div class="pi-bottom">
          <div class="pi-rl">${p.result_label}</div>
          <div class="pi-rv">${p.result}</div>
          <span class="pi-cta">View Case Study <i class="ph ph-arrow-right"></i></span>
        </div>
      </div>`;
    row.innerHTML = even ? imgPane + infoPane : infoPane + imgPane;
    row.addEventListener('click', () => openCS(p));
    list.appendChild(row);
    if (i < PROJECTS.length - 1) {
      const gap = document.createElement('div');
      gap.style.height = '2px';
      list.appendChild(gap);
    }
  });
  initReveal();
}
buildProjects();

/* ── CASE STUDY ── */
const cs = document.getElementById('cs');
const csBody = document.getElementById('csBody');
function openCS(p) {
  const all = [p.img, ...p.gallery];
  csBody.innerHTML = `
    <div class="cs-hero">
      <div>
        <div class="cs-cat">${p.category} · ${p.year}</div>
        <h1 class="cs-title">${p.name}</h1>
        <p class="cs-hl">${p.headline}</p>
        <div class="cs-tags">${p.tags.map(t=>`<span class="pill">${t}</span>`).join(' ')}</div>
      </div>
      <div>
        <p class="cs-desc">${p.desc}</p>
        <div class="cs-result">
          <div class="cs-rl">${p.result_label}</div>
          <div class="cs-rv">${p.result}</div>
        </div>
      </div>
    </div>
    <div class="cs-gallery">
      ${all.map(src=>`<div class="cs-gi"><img src="${src}" alt="${p.name}" loading="lazy"></div>`).join('')}
    </div>`;
  cs.classList.add('open');
  document.body.style.overflow = 'hidden';
  cs.scrollTop = 0;
}
document.getElementById('csX').addEventListener('click', closeCS);
cs.addEventListener('click', e => { if (e.target === cs) closeCS(); });
document.addEventListener('keydown', e => { if (e.key === 'Escape') closeCS(); });
function closeCS() { cs.classList.remove('open'); document.body.style.overflow = ''; }

initReveal();